<?php declare(strict_types=1); namespace app\admin\command; use think\console\Command; use think\console\Input; use think\console\Output; use app\common\service\plugin\PluginPaymentService; class PluginSettleCommand extends Command { protected function configure() { $this->setName("plugin:settle")->setDescription("插件月度分成结算"); } protected function execute(Input $input, Output $output) { $output->writeln("开始插件月度结算..."); $svc = new PluginPaymentService(); $result = $svc->monthlySettle(); $output->writeln($result["msg"] ?? "结算完成"); $output->writeln("月度结算完成"); return 0; } }
